import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Navbar from './components/Navbar';
import Login from './pages/Login';
import Register from './pages/Register';
import api from './api/axiosConfig';

const fallbackProducts = [
  { id: 1, name: "Gaming Laptop", description: "RTX 4080 | 32GB RAM | 1TB NVMe. Ultra-fast performance.", price: 169999, categoryName: "Tech", imageUrl: "https://images.unsplash.com/photo-1593640408182-31c70c8268f5?auto=format&w=800&q=80" },
  { id: 2, name: "Wireless Headphones", description: "Noise Cancelling Wireless Audio with 40h battery.", price: 12999, categoryName: "Tech", imageUrl: "https://images.unsplash.com/photo-1505740420928-5e560c06d30e?auto=format&w=800&q=80" },
  { id: 3, name: "Leather Jacket", description: "Premium 100% Genuine Leather. Stylish and durable.", price: 5999, categoryName: "Fashion", imageUrl: "https://images.unsplash.com/photo-1551028719-00167b16eac5?auto=format&w=800&q=80" },
  { id: 4, name: "Sports Sneakers", description: "Ultra Comfort Running Shoes. Perfect for athletics.", price: 3499, categoryName: "Footwears", imageUrl: "https://images.unsplash.com/photo-1542291026-7eec264c27ff?auto=format&w=800&q=80" },
  { id: 5, name: "Espresso Maker", description: "Smart Wifi Enabled Espresso Machine for your kitchen.", price: 15499, categoryName: "Appliances", imageUrl: "https://images.unsplash.com/photo-1517048676732-d65bc937f952?auto=format&w=800&q=80" },
  { id: 6, name: "Smart Watch", description: "Waterproof fitness tracker with heart monitoring.", price: 4999, categoryName: "Tech", imageUrl: "https://images.unsplash.com/photo-1523275335684-37898b6baf30?auto=format&w=800&q=80" }
];

const Home = () => {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    api.get('/products')
      .then(res => {
          if(res.data && res.data.length > 0) {
              setProducts(res.data);
          } else {
              setProducts(fallbackProducts); // Show cards anyway
          }
      })
      .catch(err => {
          console.log("Backend not active. Loading presentation fallback data.");
          setProducts(fallbackProducts); // Ensure presentation works
      });
  }, []);

  return (
    <div className="py-12 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto">
      <div className="text-center mb-12">
        <h1 className="text-5xl font-extrabold text-gray-900 mb-4 tracking-tight">Welcome to SmartPoint</h1>
        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
          Discover handpicked products with unbeatable prices across Top Categories!
        </p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
        {products.map(p => (
          <div key={p.id} className="bg-white rounded-2xl shadow-[0_4px_20px_rgb(0,0,0,0.08)] hover:shadow-[0_8px_30px_rgb(0,0,0,0.12)] transition-all duration-300 overflow-hidden border border-gray-100 flex flex-col group">
            <div className="relative overflow-hidden w-full h-56 bg-gray-100">
              <img src={p.imageUrl} alt={p.name} className="h-full w-full object-cover group-hover:scale-105 transition-transform duration-500" />
              <div className="absolute top-3 left-3 bg-white/90 backdrop-blur-sm text-primary text-xs font-bold px-3 py-1 rounded-full uppercase shadow-sm tracking-wider">
                {p.categoryName || 'General'}
              </div>
            </div>

            <div className="p-6 flex flex-col flex-grow">
              <h3 className="text-xl font-bold text-gray-900 mb-2 leading-tight">{p.name}</h3>
              <p className="text-gray-500 text-sm mb-5 line-clamp-2 leading-relaxed flex-grow">{p.description}</p>

              <div className="flex items-center justify-between mb-5">
                <span className="text-3xl font-extrabold text-gray-900">₹{p.price.toLocaleString("en-IN")}</span>
              </div>

              <div className="flex gap-3 mt-auto">
                <button className="flex-1 bg-indigo-50 hover:bg-indigo-100 text-primary font-bold py-2.5 px-4 rounded-xl transition-colors duration-200">
                  Add to Cart
                </button>
                <button className="flex-1 bg-primary hover:bg-secondary text-white font-bold py-2.5 px-4 rounded-xl shadow-md transition-all duration-200 hover:-translate-y-0.5">
                  Buy Now
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const Dashboard = () => {
  const role = localStorage.getItem('role');
  const [product, setProduct] = useState({ name: '', description: '', price: '', stock: '', categoryId: '', imageUrl: '' });
  const [message, setMessage] = useState('');

  const handleAddProduct = async (e) => {
    e.preventDefault();
    try {
      await api.post('/products', {
        name: product.name,
        description: product.description,
        price: parseFloat(product.price),
        stock: parseInt(product.stock),
        categoryId: product.categoryId ? parseInt(product.categoryId) : null,
        imageUrl: product.imageUrl
      });
      setMessage('Product listed successfully!');
      setProduct({ name: '', description: '', price: '', stock: '', categoryId: '', imageUrl: '' });
    } catch (err) {
      setMessage('Error listing product. Ensure you are an Admin.');
    }
  };

  return (
    <div className="py-12 px-8 max-w-7xl mx-auto">
      <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100 mb-8">
        <h1 className="text-4xl font-bold mb-4 text-gray-900">Dashboard</h1>
        <p className="text-lg text-gray-600">Welcome back to SmartPoint! Authentication functions are securely running here.</p>
      </div>

      {role === 'ADMIN' && (
        <div className="bg-white p-8 rounded-2xl shadow-lg border border-indigo-100">
          <h2 className="text-2xl font-bold mb-4 text-indigo-700">Admin Area: List a New Product</h2>
          {message && <p className="mb-4 text-primary font-semibold">{message}</p>}
          <form onSubmit={handleAddProduct} className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <input type="text" placeholder="Product Name" required className="input-field" value={product.name} onChange={e => setProduct({...product, name: e.target.value})} />
            <input type="text" placeholder="Image URL (e.g. Unsplash URL)" className="input-field" value={product.imageUrl} onChange={e => setProduct({...product, imageUrl: e.target.value})} />
            <input type="number" step="0.01" placeholder="Price ($)" required className="input-field" value={product.price} onChange={e => setProduct({...product, price: e.target.value})} />
            <input type="number" placeholder="Inventory Stock Qty" required className="input-field" value={product.stock} onChange={e => setProduct({...product, stock: e.target.value})} />
            <select className="input-field sm:col-span-2" value={product.categoryId} onChange={e => setProduct({...product, categoryId: e.target.value})}>
              <option value="">Select Category (Optional)</option>
              <option value="1">Tech</option>
              <option value="2">Fashion</option>
              <option value="3">Footwears</option>
              <option value="4">Appliances</option>
            </select>
            <textarea placeholder="Product Description" required className="input-field sm:col-span-2" rows="3" value={product.description} onChange={e => setProduct({...product, description: e.target.value})}></textarea>
            <button type="submit" className="btn-primary sm:col-span-2 py-3">List Product to Marketplace</button>
          </form>
        </div>
      )}
    </div>
  );
};

function App() {
  return (
    <Router>
      <div className="font-sans min-h-screen flex flex-col bg-slate-50">
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/dashboard" element={<Dashboard />} />
          </Routes>
        </main>
        <footer className="bg-white border-t border-gray-200 py-8 mt-12">
            <p className="text-center text-gray-400 text-sm font-medium">© 2026 SmartPoint App. Premium Marketplace.</p>
        </footer>
      </div>
    </Router>
  );
}

export default App;
